#include <stdio.h>
#define MOD 1000000007
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        if (N % 2 == 1) {
            printf("0\n");
            continue;
        }
        int sum = 0;
        for (int i = 1; i <= N / 2; i++) {
            if ((N / 2 - i) % 2 == 0) {
                sum = (sum + 1) % MOD;
            }
        }
        printf("%d\n", sum);
    }
    return 0;
}

