import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            if (N % 2 == 1) {
                System.out.println(0);
                continue;
            }
            int sum = 0;
            for (int i = 1; i <= N / 2; i++) {
                if ((N / 2 - i) % 2 == 0) {
                    sum = (sum + 1) % 1000000007;
                }
            }
            System.out.println(sum);
        }
    }
}

